import{_ as e,o as r,c as h,ah as i}from"./chunks/framework.BNo2o5Ln.js";const b=JSON.parse('{"title":"缓存架构","description":"","frontmatter":{"title":"缓存架构","order":1},"headers":[],"relativePath":"server/arch/cache/index.md","filePath":"server/arch/cache/index.md"}'),l={name:"server/arch/cache/index.md"};function d(n,a,t,s,o,c){return r(),h("div",null,[...a[0]||(a[0]=[i('<h1 id="缓存架构" tabindex="-1">缓存架构 <a class="header-anchor" href="#缓存架构" aria-label="Permalink to “缓存架构”">​</a></h1><p>缓存是存储数据子集的高速存储层，访问速度比主存储快。缓存是提升系统性能、降低数据库负载、提高响应速度的有效手段。</p><h2 id="缓存原理" tabindex="-1">缓存原理 <a class="header-anchor" href="#缓存原理" aria-label="Permalink to “缓存原理”">​</a></h2><h3 id="局部性原理" tabindex="-1">局部性原理 <a class="header-anchor" href="#局部性原理" aria-label="Permalink to “局部性原理”">​</a></h3><p>局部性原理是缓存的理论基础。时间局部性：最近访问的数据很可能再次被访问。空间局部性：最近访问数据附近的数据很可能被访问。</p><p>缓存的本质是用空间换时间，通过存储热点数据，减少访问慢速存储（数据库、磁盘）的次数。</p><h3 id="缓存命中率" tabindex="-1">缓存命中率 <a class="header-anchor" href="#缓存命中率" aria-label="Permalink to “缓存命中率”">​</a></h3><p>缓存命中率 = 缓存命中次数 / 总访问次数。命中率越高，缓存效果越好。缓存命中率取决于：数据分布（是否集中热点）、缓存容量（能否存储热点）、淘汰策略（是否保留热点）、预取策略（是否提前加载）。</p><h2 id="缓存模式" tabindex="-1">缓存模式 <a class="header-anchor" href="#缓存模式" aria-label="Permalink to “缓存模式”">​</a></h2><h3 id="cache-aside-旁路缓存" tabindex="-1">Cache-Aside（旁路缓存） <a class="header-anchor" href="#cache-aside-旁路缓存" aria-label="Permalink to “Cache-Aside（旁路缓存）”">​</a></h3><p>Cache-Aside 是最常用的缓存模式。读：先读缓存，缓存未命中则读数据库，然后写入缓存。写：先更新数据库，然后删除缓存（或更新缓存）。</p><p>Cache-Aside 的问题：缓存未命中时有缓存击穿风险（大量请求同时访问不存在的 key）。解决方案：布隆过滤器（快速判断 key 是否存在）、缓存空值（防止重复查询数据库）。</p><h3 id="read-through-读穿透" tabindex="-1">Read-Through（读穿透） <a class="header-anchor" href="#read-through-读穿透" aria-label="Permalink to “Read-Through（读穿透）”">​</a></h3><p>Read-Through 是缓存层负责从数据库加载数据。读：先读缓存，缓存未命中则缓存层读数据库并写入缓存。应用只与缓存交互，不直接访问数据库。</p><p>Read-Through 的好处：简化应用逻辑，缓存层统一管理数据加载。Read-Through 的代价：缓存层需要实现数据库访问逻辑。</p><h3 id="write-through-写穿透" tabindex="-1">Write-Through（写穿透） <a class="header-anchor" href="#write-through-写穿透" aria-label="Permalink to “Write-Through（写穿透）”">​</a></h3><p>Write-Through 是写数据时同时更新缓存和数据库。写：先更新数据库，然后更新缓存。缓存和数据库保持一致。</p><p>Write-Through 的好处：数据一致性强，缓存始终是最新的。Write-Through 的代价：写操作延迟高（需要同时更新缓存和数据库）。</p><h3 id="write-behind-异步写" tabindex="-1">Write-Behind（异步写） <a class="header-anchor" href="#write-behind-异步写" aria-label="Permalink to “Write-Behind（异步写）”">​</a></h3><p>Write-Behind 是写数据时只更新缓存，异步批量更新数据库。写：更新缓存，缓存层异步批量更新数据库。</p><p>Write-Behind 的好处：写操作延迟低，缓存层可以合并写操作。Write-Behind 的代价：数据可能丢失（缓存层崩溃时）、一致性弱（缓存和数据库可能不一致）。</p><h2 id="缓存淘汰策略" tabindex="-1">缓存淘汰策略 <a class="header-anchor" href="#缓存淘汰策略" aria-label="Permalink to “缓存淘汰策略”">​</a></h2><h3 id="lru-least-recently-used" tabindex="-1">LRU（Least Recently Used） <a class="header-anchor" href="#lru-least-recently-used" aria-label="Permalink to “LRU（Least Recently Used）”">​</a></h3><p>LRU 淘汰最近最少使用的数据。LRU 的实现：哈希表 + 双向链表。哈希表提供 O(1) 查找，双向链表记录访问顺序。</p><p>LRU 的问题：实现复杂（需要维护双向链表）、内存占用大（每个缓存项需要前驱和后继指针）。LRU 的改进：LRU-K（考虑最近 K 次访问）、Two Queues（二级 LRU）。</p><h3 id="lfu-least-frequently-used" tabindex="-1">LFU（Least Frequently Used） <a class="header-anchor" href="#lfu-least-frequently-used" aria-label="Permalink to “LFU（Least Frequently Used）”">​</a></h3><p>LFU 淘汰访问频率最低的数据。LFU 的实现：哈希表 + 优先队列（最小堆）。优先队列按访问频率排序，淘汰频率最低的数据。</p><p>LFU 的问题：新数据可能被淘汰（访问频率低但可能是热点）、实现复杂（需要维护优先队列）。LFU 的改进：LFU with Dynamic Aging（考虑时间因素，降低旧数据的频率）。</p><h3 id="fifo-first-in-first-out" tabindex="-1">FIFO（First In First Out） <a class="header-anchor" href="#fifo-first-in-first-out" aria-label="Permalink to “FIFO（First In First Out）”">​</a></h3><p>FIFO 淘汰最先加入的数据。FIFO 的实现：队列。FIFO 的问题：可能淘汰热点数据（热点数据是最先加入的）、不考虑访问频率。</p><h3 id="random-随机淘汰" tabindex="-1">Random（随机淘汰） <a class="header-anchor" href="#random-随机淘汰" aria-label="Permalink to “Random（随机淘汰）”">​</a></h3><p>Random 随机淘汰数据。Random 的好处：实现简单、无额外开销。Random 的代价：可能淘汰热点数据、缓存命中率低。</p><h2 id="缓存问题" tabindex="-1">缓存问题 <a class="header-anchor" href="#缓存问题" aria-label="Permalink to “缓存问题”">​</a></h2><h3 id="缓存穿透" tabindex="-1">缓存穿透 <a class="header-anchor" href="#缓存穿透" aria-label="Permalink to “缓存穿透”">​</a></h3><p>缓存穿透是查询不存在的数据，缓存和数据库都没有，导致每次请求都穿透到数据库。解决方案：布隆过滤器（快速判断 key 是否不存在）、缓存空值（缓存不存在的 key）、限流（防止恶意攻击）。</p><h3 id="缓存击穿" tabindex="-1">缓存击穿 <a class="header-anchor" href="#缓存击穿" aria-label="Permalink to “缓存击穿”">​</a></h3><p>缓存击穿是热点 key 过期，大量请求同时查询该 key，导致数据库压力突增。解决方案：加锁（只允许一个请求查询数据库）、热点 key 不过期（延长过期时间）、互斥锁（分布式锁）。</p><h3 id="缓存雪崩" tabindex="-1">缓存雪崩 <a class="header-anchor" href="#缓存雪崩" aria-label="Permalink to “缓存雪崩”">​</a></h3><p>缓存雪崩是大量 key 同时过期，导致大量请求穿透到数据库。解决方案：过期时间加随机值（避免同时过期）、多级缓存（本地缓存 + 分布式缓存）、缓存高可用（集群部署）。</p><h2 id="缓存一致性" tabindex="-1">缓存一致性 <a class="header-anchor" href="#缓存一致性" aria-label="Permalink to “缓存一致性”">​</a></h2><h3 id="一致性要求" tabindex="-1">一致性要求 <a class="header-anchor" href="#一致性要求" aria-label="Permalink to “一致性要求”">​</a></h3><p>强一致性：缓存和数据库的数据始终一致。最终一致性：缓存和数据库的数据最终一致，允许短暂不一致。弱一致性：不保证数据一致。</p><h3 id="一致性方案" tabindex="-1">一致性方案 <a class="header-anchor" href="#一致性方案" aria-label="Permalink to “一致性方案”">​</a></h3><p>更新数据库后更新缓存：可能不一致（更新缓存失败）、延迟高（需要等待缓存更新）。更新数据库后删除缓存：可能不一致（删除缓存前有读请求）、延迟低。</p><p>延迟双删：先删除缓存，更新数据库，延迟后再删除缓存。延迟双删可以减少不一致窗口期。</p><p>监听 Binlog：通过监听数据库的 Binlog，异步更新缓存。监听 Binlog 可以保证最终一致性，但实现复杂（需要 Canal、Debezium 等工具）。</p><h2 id="缓存类型" tabindex="-1">缓存类型 <a class="header-anchor" href="#缓存类型" aria-label="Permalink to “缓存类型”">​</a></h2><h3 id="本地缓存" tabindex="-1">本地缓存 <a class="header-anchor" href="#本地缓存" aria-label="Permalink to “本地缓存”">​</a></h3><p>本地缓存是应用进程内的缓存，如 Guava、Caffeine、Ehcache。本地缓存的优势：速度快（无网络开销）、简单（无需额外部署）。本地缓存的问题：容量有限（受限于进程内存）、多实例不一致（每个实例的缓存独立）。</p><h3 id="分布式缓存" tabindex="-1">分布式缓存 <a class="header-anchor" href="#分布式缓存" aria-label="Permalink to “分布式缓存”">​</a></h3><p>分布式缓存是独立的缓存服务，如 Redis、Memcached。分布式缓存的优势：容量大（可扩展）、多实例共享（所有实例访问同一缓存）。分布式缓存的问题：网络开销、序列化开销、单点故障（需要集群）。</p><h3 id="多级缓存" tabindex="-1">多级缓存 <a class="header-anchor" href="#多级缓存" aria-label="Permalink to “多级缓存”">​</a></h3><p>多级缓存是本地缓存 + 分布式缓存的组合。读：先读本地缓存，未命中则读分布式缓存，再未命中则读数据库。写：更新数据库，删除分布式缓存，删除本地缓存。</p><p>多级缓存的好处：减少网络开销（本地缓存命中率高）、降低分布式缓存压力。多级缓存的问题：一致性复杂（多级缓存同步）、本地缓存占用内存。</p><h2 id="缓存应用" tabindex="-1">缓存应用 <a class="header-anchor" href="#缓存应用" aria-label="Permalink to “缓存应用”">​</a></h2><h3 id="页面缓存" tabindex="-1">页面缓存 <a class="header-anchor" href="#页面缓存" aria-label="Permalink to “页面缓存”">​</a></h3><p>缓存渲染后的 HTML 页面，减少数据库查询和页面渲染。适用场景：静态页面、访问量大的首页、新闻列表。</p><h3 id="对象缓存" tabindex="-1">对象缓存 <a class="header-anchor" href="#对象缓存" aria-label="Permalink to “对象缓存”">​</a></h3><p>缓存查询结果（如用户信息、商品信息），减少数据库查询。适用场景：热点数据、读多写少的数据。</p><h3 id="查询缓存" tabindex="-1">查询缓存 <a class="header-anchor" href="#查询缓存" aria-label="Permalink to “查询缓存”">​</a></h3><p>缓存数据库查询结果（如 SELECT 结果），减少数据库查询。适用场景：复杂查询、频繁查询。</p><p>缓存是提升系统性能的有效手段，但也会引入一致性问题。理解缓存的模式、淘汰策略、一致性问题，有助于设计合适的缓存架构。</p>',62)])])}const f=e(l,[["render",d]]);export{b as __pageData,f as default};
